async (page) => {
  // Walk north in steps toward Forester at (216, 114)
  for (let targetY = 148; targetY >= 120; targetY -= 10) {
    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 207, y: targetY});
    await page.waitForTimeout(3000);
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    const questNPCs = await page.evaluate(() => window.__latestGameState.nearby_entities.filter(e => e.quest_npc).map(e => ({name: e.name, dist: e.distance})));
    console.log(`Pos: ${JSON.stringify(pos)}, QuestNPCs: ${JSON.stringify(questNPCs)}`);
    if (pos.y <= 120) break;
  }
  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {pos: s.player_position, questNPCs: s.nearby_entities.filter(e => e.quest_npc).map(e => ({name: e.name, dist: e.distance, on_screen: e.on_screen}))};
  });
  return JSON.stringify(finalState, null, 2);
}

async (page) => {
  // Click the Rat that's on screen
  await page.evaluate(() => {
    const s = window.__latestGameState;
    const rat = s.nearby_entities.find(e => e.type === 3 && e.name === 'Rat' && e.on_screen && e.click_x);
    if (rat) {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: rat.click_x, clientY: rat.click_y, bubbles: true, ctrlKey: false }));
    }
  });
  await page.waitForTimeout(7000);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {
      pos: s.player_position,
      hp: s.player_stats.hp,
      xp: s.player_stats.experience,
      level: s.player_stats.level,
      last_combat: s.last_combat,
      last_xp: s.last_xp_event,
      target: s.current_target ? {name: s.current_target.name, hp: s.current_target.hp} : null
    };
  });
  return JSON.stringify(state, null, 2);
}

