async (page) => {
  // Chop trees systematically - 15 more hits
  let totalLogs = 4;
  for (let i = 0; i < 15; i++) {
    await page.evaluate(() => {
      // Find oak entity in game data directly
      const s = window.__latestGameState;
      const treeNames = ['Oak', 'Spruce', 'Pine', 'Willow'];
      const tree = s.nearby_entities.find(e => treeNames.some(n => e.name && e.name.includes(n)));
      if (tree && tree.click_x && tree.on_screen) {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: tree.click_x, clientY: tree.click_y, bubbles: true, ctrlKey: false }));
      } else {
        // Use __clickEntity on E0 which is usually closest entity
        window.__clickEntity('E0');
      }
    });
    await page.waitForTimeout(3500);

    const logs = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.name === 'Logs').length);
    if (logs >= 10) { totalLogs = logs; break; }
    totalLogs = logs;
  }

  const finalState = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {
      logCount: s.inventory.filter(i => i.name === 'Logs').length,
      inventory: s.inventory.map(i => i.name),
      pos: s.player_position,
      hp: s.player_stats.hp
    };
  });
  return JSON.stringify(finalState, null, 2);
}

async (page) => {
  for (let i = 0; i < 12; i++) {
    await page.evaluate(() => {
      const s = window.__latestGameState;
      const treeNames = ['Oak', 'Spruce', 'Pine', 'Willow'];
      // Try current target first if tree
      const t = s.current_target;
      if (t && t.click_x && t.on_screen && treeNames.some(n => t.name && t.name.includes(n))) {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: t.click_x, clientY: t.click_y, bubbles: true, ctrlKey: false}));
        return;
      }
      // Find any nearby entity that's a tree (by name pattern)
      const tree = s.nearby_entities.find(e => treeNames.some(n => e.name && e.name.includes(n)));
      if (tree) {
        // Use __clickEntity approach - find its label
        const label = window.__latestAsciiMap && window.__latestAsciiMap.entities
          ? Object.keys(window.__latestAsciiMap.entities).find(k => window.__latestAsciiMap.entities[k] && window.__latestAsciiMap.entities[k].id === tree.id)
          : null;
        if (label) window.__clickEntity(label);
        else if (tree.click_x && tree.on_screen) {
          document.getElementById('canvas').dispatchEvent(new MouseEvent('click', {clientX: tree.click_x, clientY: tree.click_y, bubbles: true, ctrlKey: false}));
        }
      }
    });
    await page.waitForTimeout(3500);
    const logs = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.name === 'Logs').length);
    if (logs >= 10) break;
  }
  const s = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {logs: gs.inventory.filter(i => i.name === 'Logs').length, inv: gs.inventory.map(i => i.name), pos: gs.player_position};
  });
  return JSON.stringify(s, null, 2);
}
